parameters.text:
=Analyze this forwarded email and extract expense information.

From: {{ $json.from.text }}
Subject: {{ $json.subject }}
Body: {{ $json.text }}
Email date: {{ $json.date }}

parameters.jsCode:
const items = $input.all();
const expenses = [];
for (const item of items) {
  const data = item.json.output || item.json;
  const expenseList = data.expenses || [];
  for (const expense of expenseList) {
    expenses.push({ json: { name: expense.name, amount: expense.amount, date: expense.date, category: expense.category } });
  }
}
return expenses;
